CREATE TYPE "application_status" AS ENUM ('draft','submitted','ai_prescreened','under_review','needs_revision','approved','rejected');
CREATE TYPE "finding_severity" AS ENUM ('info','warning','critical');
CREATE TYPE "finding_source" AS ENUM ('ai','deterministic_rule','reviewer');
CREATE TABLE "tenants" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "name" text NOT NULL, "created_at" timestamptz NOT NULL DEFAULT now());
CREATE TABLE "users" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "tenant_id" uuid NOT NULL REFERENCES "tenants"("id"), "email" text NOT NULL, "name" text NOT NULL, "role" text NOT NULL, "created_at" timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX "users_tenant_email_uq" ON "users" ("tenant_id", "email");
CREATE TABLE "applications" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "tenant_id" uuid NOT NULL REFERENCES "tenants"("id"), "reference_no" text NOT NULL, "applicant_name" text NOT NULL, "parcel_no" text NOT NULL, "development_type" text NOT NULL, "region" text NOT NULL, "status" application_status NOT NULL DEFAULT 'draft', "assigned_reviewer_id" uuid REFERENCES "users"("id"), "version" integer NOT NULL DEFAULT 1, "submitted_at" timestamptz, "created_at" timestamptz NOT NULL DEFAULT now(), "updated_at" timestamptz NOT NULL DEFAULT now());
CREATE UNIQUE INDEX "applications_tenant_reference_uq" ON "applications" ("tenant_id", "reference_no");
CREATE INDEX "applications_tenant_status_idx" ON "applications" ("tenant_id", "status");
CREATE TABLE "documents" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "tenant_id" uuid NOT NULL REFERENCES "tenants"("id"), "application_id" uuid NOT NULL REFERENCES "applications"("id"), "name" text NOT NULL, "storage_key" text NOT NULL, "mime_type" text NOT NULL, "version" integer NOT NULL DEFAULT 1, "uploaded_at" timestamptz NOT NULL DEFAULT now());
CREATE TABLE "findings" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "tenant_id" uuid NOT NULL REFERENCES "tenants"("id"), "application_id" uuid NOT NULL REFERENCES "applications"("id"), "source" finding_source NOT NULL, "severity" finding_severity NOT NULL, "code" text NOT NULL, "title" text NOT NULL, "detail" text NOT NULL, "evidence" jsonb NOT NULL DEFAULT '{}'::jsonb, "resolved" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL DEFAULT now());
CREATE TABLE "decisions" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "tenant_id" uuid NOT NULL REFERENCES "tenants"("id"), "application_id" uuid NOT NULL REFERENCES "applications"("id"), "reviewer_id" uuid NOT NULL REFERENCES "users"("id"), "action" text NOT NULL, "note" text NOT NULL, "override_justification" text, "created_at" timestamptz NOT NULL DEFAULT now());
CREATE TABLE "audit_events" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(), "tenant_id" uuid NOT NULL REFERENCES "tenants"("id"), "application_id" uuid REFERENCES "applications"("id"), "actor_id" uuid REFERENCES "users"("id"), "event_type" text NOT NULL, "payload" jsonb NOT NULL DEFAULT '{}'::jsonb, "created_at" timestamptz NOT NULL DEFAULT now());
CREATE INDEX "audit_tenant_application_idx" ON "audit_events" ("tenant_id", "application_id", "created_at");
